vi":"Tiện ích"},"image":"https://cdn.pico.vn/2023/08/24/169285064875869394076.svg","channels":["b2c","b2e"],"content":{"vi":""},"policy":false,"priority":false,"order":17,"values":[{"_id":"64e6da03bb8be289fb77da06","order":1,"value":{"vi":"Giặt nước nóng"}},{"_id":"64e6da03bb8be289fb77da07","order":1,"value":{"vi":"Giặt hơi nước"}},{"_id":"64e6da03bb8be289fb77da08","order":1,"value":{"vi":"Inverter tiết kiệm điện"}},{"_id":"64e6da03bb8be289fb77da09","order":1,"value":{"vi":"Chạy êm và bền (truyền động trực tiếp)"}},{"_id":"64e9734370f95f03922247fb","order":1,"value":{"vi":"Khóa trẻ em"}},{"_id":"66c83c968f277a3590939610","order":1,"value":{"vi":"Kết nối Wifi "}},{"_id":"68afcbb007b4d41c74321976","order":1,"value":{"vi":"Tùy chỉnh lượng nước giặt và nước xả"}}]},{"_id":"64e6d9a9bb8be289fb77d9d7","valueIds":[],"value":{"vi":"Giặt AI\nVải bông\nVải bông+\nTurboWash 39\nĐồ hỗn hợp\nGiặt nhanh 14p\nGiặt đồ tinh xảo\nEasy Care\nGiặt tay/ Đồ len\nMicroplastic Care\nĐồ thể thao\nNgừa dị ứng\nLàm sạch lồng giặt\nChu trình tải về\n"},"selected":true,"type":"input","name":{"vi":"Chương trình giặt"},"channels":["b2c","b2e"],"content":{"vi":""},"policy":false,"priority":false,"order":18,"values":[]},{"_id":"64e6c7e9bb8be289fb77d247","valueIds":["64e6c7e9bb8be289fb77d24d"],"selected":true,"type":"singleSelect","name":{"vi":"Khoảng giá"},"image":"https://cdn.pico.vn/2023/08/24/169284633678892385668.svg","channels":["b2c","b2e"],"content":{"vi":""},"policy":false,"priority":false,"order":20,"values":[{"_id":"64e6c7e9bb8be289fb77d24d","order":1,"value":{"vi":"Từ 10 - 20 triệu"}}]},{"_id":"64e6e45cbb8be289fb77df0c","valueIds":[],"value":{"vi":"100"},"selected":true,"type":"input","name":{"vi":"Sản phẩm bảo hành miễn phí"},"image":"https://cdn.pico.vn/2025/11/20/1763628996092977543.svg","desktopIcon":"https://cdn.pico.vn/2025/11/15/176317495565719224599.svg","unit":{"_id":"64e6e295bb8be289fb77deb6","name":{"vi":"%"}},"channels":["b2c"],"content":{"vi":"\u003ch1\u003e\u003cstrong\u003eCH\u0026Iacute;NH S\u0026Aacute;CH BẢO H\u0026Agrave;NH\u003c/strong\u003e\u003c/h1\u003e\n\n\u003ch2\u003e\u003cspan style=\"font-size:14px\"\u003e\u003cstrong\u003eBảo h\u0026agrave;nh sản phẩm l\u0026agrave;:\u003c/strong\u003e\u0026nbsp;khắc phục những lỗi hỏng h\u0026oacute;c, sự cố kỹ thuật xảy ra do lỗi của H\u0026atilde;ng sản xuất.\u003c/span\u003e\u003c/h2\u003e\n\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e\n\n\u003ch2\u003e\u003cstrong\u003eI/ Những trường hợp được bảo h\u0026agrave;nh miễn ph\u0026iacute;:\u003c/strong\u003e\u003c/h2\u003e\n\n\u003ch2\u003e\u003cstrong\u003e​​​​​​​\u003c/strong\u003e\u003cbr /\u003e\n\u003cspan style=\"font-size:14px\"\u003e​​​​\u0026nbsp;- Sản phẩm được bảo h\u0026agrave;nh miễn ph\u0026iacute; nếu sản phẩm đ\u0026oacute; c\u0026ograve;n trong thời hạn bảo h\u0026agrave;nh của H\u0026atilde;ng sản xuất.\u003cbr /\u003e\n\u0026nbsp;- Thời hạn bảo h\u0026agrave;nh được t\u0026iacute;nh từ ng\u0026agrave;y giao h\u0026agrave;ng v\u0026agrave; theo quy định bảo h\u0026agrave;nh của từng H\u0026atilde;ng sản xuất đối với tất cả c\u0026aacute;c sự cố về mặt kỹ thuật.\u003cbr /\u003e\n\u0026nbsp;- C\u0026oacute; Phiếu bảo h\u0026agrave;nh v\u0026agrave; Tem bảo h\u0026agrave;nh của H\u0026atilde;ng sản xuất tr\u0026ecirc;n sản phẩm (theo quy định của từng H\u0026atilde;ng sản xuất).\u003c/span\u003e\u003c/h2\u003e\n\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e\n\n\u003cp\u003e\u003cspan style=\"font-size:14px\"\u003e\u003cstrong\u003eDanh s\u0026aacute;ch sản phẩm được phục vụ bảo h\u0026agrave;nh tại nh\u0026agrave;:\u003c/strong\u003e\u003c/span\u003e\u003c/p\u003e\n\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e\n\n\u003cp\u003e\u003cimg src=\"https://cdn.pico.vn/2024/11/21/173215940725764303273.png\" style=\"height:345px; width:612px\" /\u003e\u003c/p\u003e\n\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e\n\n\u003cp\u003e-​​​​​\u0026nbsp;Những sản phẩm thuộc danh s\u0026aacute;ch sản phẩm được phục vụ bảo h\u0026agrave;nh tại nh\u0026agrave;, t\u0026ugrave;y thuộc v\u0026agrave;o mức độ hư hỏng của sản phẩm v\u0026agrave; quy định bảo h\u0026agrave;nh của H\u0026atilde;ng sản xuất: Kỹ thuật vi\u0026ecirc;n của C\u0026ocirc;ng ty cổ phần Pico Retail sẽ trực tiếp khắc phục sự cố tại nh\u0026agrave; hoặc thay mặt Qu\u0026yacute; kh\u0026aacute;ch mang sản phẩm tới Trung T\u0026acirc;m Bảo H\u0026agrave;nh của H\u0026atilde;ng hoặc th\u0026ocirc;ng b\u0026aacute;o với H\u0026atilde;ng để đến bảo h\u0026agrave;nh sản phẩm cho Qu\u0026yacute; kh\u0026aacute;ch.\u003c/p\u003e\n\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e\n\n\u003cp\u003e- Những sản phẩm kh\u0026ocirc;ng thuộc danh s\u0026aacute;ch sản phẩm được bảo h\u0026agrave;nh tại nh\u0026agrave; (nằm trong khả năng chuy\u0026ecirc;n chở của Qu\u0026yacute; kh\u0026aacute;ch): Qu\u0026yacute; kh\u0026aacute;ch h\u0026agrave;ng vui l\u0026ograve;ng mang sản phẩm đến Trung t\u0026acirc;m Chăm s\u0026oacute;c kh\u0026aacute;ch h\u0026agrave;ng của C\u0026ocirc;ng ty cổ phần Pico Retail hoặc tới Trung T\u0026acirc;m Bảo H\u0026agrave;nh của H\u0026atilde;ng sản xuất để được phục vụ nhanh ch\u0026oacute;ng hơn.\u0026nbsp;\u003c/p\u003e\n\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e\n\n\u003cp\u003e\u003cspan style=\"font-size:16px\"\u003e\u003cstrong\u003eHướng dẫn thủ tục khi bảo h\u0026agrave;nh:\u003c/strong\u003e\u003c/span\u003e\u003c/p\u003e\n\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e\n\n\u003cp\u003e-\u0026nbsp;Đối với sản phẩm thuộc danh s\u0026aacute;ch được bảo h\u0026agrave;nh tại nh\u0026agrave;: Qu\u0026yacute; kh\u0026aacute;ch h\u0026agrave;ng li\u0026ecirc;n lạc trực tiếp với H\u0026atilde;ng sản xuất\u0026nbsp; hoặc li\u0026ecirc;n hệ với\u0026nbsp;Trung t\u0026acirc;m chăm s\u0026oacute;c Kh\u0026aacute;ch h\u0026agrave;ng của C\u0026ocirc;ng ty CP Pico Retail, C\u0026ocirc;ng ty CP Pico Retail sẽ thay mặt Qu\u0026yacute; kh\u0026aacute;ch li\u0026ecirc;n lạc với H\u0026atilde;ng để đến bảo h\u0026agrave;nh cho Qu\u0026yacute; kh\u0026aacute;ch.\u003c/p\u003e\n\n\u003cp\u003e- Đổi với sản phẩm kh\u0026ocirc;ng thuộc danh s\u0026aacute;ch được bảo h\u0026agrave;nh tại nh\u0026agrave;:\u003c/p\u003e\n\n\u003cp\u003e+ Qu\u0026yacute; kh\u0026aacute;ch h\u0026agrave;ng li\u0026ecirc;n lạc trực tiếp với H\u0026atilde;ng hoặc gửi sản phẩm đến Trung T\u0026acirc;m Bảo H\u0026agrave;nh gần nhất của H\u0026atilde;ng. Qu\u0026yacute; kh\u0026aacute;ch h\u0026agrave;ng tự chịu chi ph\u0026iacute; chuyển h\u0026agrave;ng.\u003cbr /\u003e\n+ Qu\u0026yacute; kh\u0026aacute;ch h\u0026agrave;ng gửi sản phẩm đến Trung t\u0026acirc;m chăm s\u0026oacute;c Kh\u0026aacute;ch h\u0026agrave;ng của C\u0026ocirc;ng ty CP Pico Retail. C\u0026ocirc;ng ty CP Pico Retail sẽ thay mặt Qu\u0026yacute; kh\u0026aacute;ch h\u0026agrave;ng chuyển bảo h\u0026agrave;nh đến Trung T\u0026acirc;m Bảo H\u0026agrave;nh gần nhất của H\u0026atilde;ng. Qu\u0026yacute; kh\u0026aacute;ch h\u0026agrave;ng tự chịu chi ph\u0026iacute; chuyển h\u0026agrave;ng.\u003c/p\u003e\n\n\u003ch2\u003e\u003cbr /\u003e\n\u003cstrong\u003eII/ Những trường hợp sau đ\u0026acirc;y sẽ kh\u0026ocirc;ng được bảo h\u0026agrave;nh (sửa chữa c\u0026oacute; t\u0026iacute;nh ph\u0026iacute;):\u003c/strong\u003e\u003c/h2\u003e\n\n\u003cp\u003e- Những sản phẩm kh\u0026ocirc;ng thể x\u0026aacute;c định được nguồn gốc mua tại C\u0026ocirc;ng ty CP Pico Retail, th\u0026igrave; C\u0026ocirc;ng ty CP Pico Retail c\u0026oacute; quyền từ chối bảo h\u0026agrave;nh.\u003c/p\u003e\n\n\u003cp\u003e- Sản phẩm đ\u0026atilde; qu\u0026aacute; thời hạn bảo h\u0026agrave;nh hoặc mất Phiếu bảo h\u0026agrave;nh.\u003c/p\u003e\n\n\u003cp\u003e- Phiếu bảo h\u0026agrave;nh,Tem bảo h\u0026agrave;nh bị r\u0026aacute;ch, kh\u0026ocirc;ng c\u0026ograve;n Tem bảo h\u0026agrave;nh, Tem bảo h\u0026agrave;nh d\u0026aacute;n đ\u0026egrave; hoặc bị sửa đổi.\u003c/p\u003e\n\n\u003cp\u003e- Phiếu bảo h\u0026agrave;nh kh\u0026ocirc;ng ghi r\u0026otilde; số Serial v\u0026agrave; ng\u0026agrave;y mua h\u0026agrave;ng.\u003c/p\u003e\n\n\u003cp\u003e- Số Serial tr\u0026ecirc;n m\u0026aacute;y v\u0026agrave; Phiếu bảo h\u0026agrave;nh kh\u0026ocirc;ng tr\u0026ugrave;ng khớp nhau hoặc kh\u0026ocirc;ng x\u0026aacute;c định được v\u0026igrave; bất kỳ l\u0026yacute; do n\u0026agrave;o.\u003c/p\u003e\n\n\u003cp\u003e- Sản phẩm bị hư hỏng do t\u0026aacute;c động cơ học l\u0026agrave;m rơi, vỡ, va đập, trầy xước, m\u0026oacute;p m\u0026eacute;o, ẩm ướt, hoen rỉ, chảy nước hoặc do hỏa hoạn, thi\u0026ecirc;n tai,\u0026hellip; g\u0026acirc;y n\u0026ecirc;n.\u003c/p\u003e\n\n\u003cp\u003e- Sản phẩm c\u0026oacute; dấu hiệu hư hỏng do chuột bọ hoặc c\u0026ocirc;n tr\u0026ugrave;ng x\u0026acirc;m nhập.\u003c/p\u003e\n\n\u003cp\u003e- Sản phẩm bị hư hỏng do sử dụng kh\u0026ocirc;ng đ\u0026uacute;ng s\u0026aacute;ch hướng dẫn, sử dụng sai điện \u0026aacute;p quy định.\u003c/p\u003e\n\n\u003cp\u003e- C\u0026aacute;c loại phụ kiện k\u0026egrave;m theo như: Điều khiển từ xa (t\u0026ugrave;y quy định bảo h\u0026agrave;nh của H\u0026atilde;ng sản xuất), Pin điều khiển, Pin CMOS, d\u0026acirc;y nguồn, d\u0026acirc;y t\u0026iacute;n hiệu, nắn d\u0026ograve;ng, đ\u0026egrave;n t\u0026iacute;n hiệu, tai nghe, quạt tr\u0026ecirc;n thiết bị, hoặc thiết bị do quạt bị hỏng g\u0026acirc;y ra ch\u0026aacute;y nổ,\u0026hellip;\u003c/p\u003e\n\n\u003cp\u003e- C\u0026aacute;c dữ liệu, t\u0026agrave;i liệu, văn bản v\u0026agrave; phần mềm cung cấp miễn ph\u0026iacute;, lưu trữ k\u0026egrave;m theo sản phẩm (kể cả trong thời gian gửi bảo h\u0026agrave;nh).\u003c/p\u003e\n\n\u003cp\u003e- Tự \u0026yacute; th\u0026aacute;o dỡ, sửa chữa bởi c\u0026aacute;c c\u0026aacute; nh\u0026acirc;n hoặc Kỹ thuật vi\u0026ecirc;n kh\u0026ocirc;ng được sự ủy quyền của C\u0026ocirc;ng ty CP Pico Retail hoặc H\u0026atilde;ng sản xuất.\u003c/p\u003e\n\n\u003ch3\u003e\u0026nbsp;\u003c/h3\u003e\n\n\u003ch3\u003e\u003cstrong\u003eIII/\u0026nbsp;Li\u0026ecirc;n hệ, thắc mắc, khiếu nại về vấn đề bảo h\u0026agrave;nh:\u003c/strong\u003e\u003cbr /\u003e\n\u0026nbsp;\u003c/h3\u003e\n\n\u003ch3\u003e\u003cspan style=\"font-size:13px\"\u003eNếu Qu\u0026yacute; kh\u0026aacute;ch chưa thấy h\u0026agrave;i l\u0026ograve;ng hoặc c\u0026oacute; thắc mắc khiếu nại g\u0026igrave; về vấn đề bảo h\u0026agrave;nh, xin Qu\u0026yacute; kh\u0026aacute;ch h\u0026agrave;ng vui l\u0026ograve;ng li\u0026ecirc;n hệ:\u003c/span\u003e\u003c/h3\u003e\n\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e\n\n\u003cp\u003e\u003cstrong\u003eTrung t\u0026acirc;m chăm s\u0026oacute;c Kh\u0026aacute;ch h\u0026agrave;ng \u0026ndash; Hệ thống si\u0026ecirc;u thị điện m\u0026aacute;y Pico\u0026nbsp;\u003c/strong\u003e\u003c/p\u003e\n\n\u003cp\u003eĐịa chỉ:\u0026nbsp;\u003cstrong\u003eSố 173 Xu\u0026acirc;n Thủy, Cầu Giấy, H\u0026agrave; Nội\u003c/strong\u003e.\u003cbr /\u003e\nĐiện thoại:\u0026nbsp;\u003cstrong\u003e(024).36277.0000 hoặc 1900 6699 .\u003c/strong\u003e\u003cbr /\u003e\nE-mail:\u0026nbsp;\u003cstrong\u003echamsockhachhang@pico.com.vn\u003c/strong\u003e\u003c/p\u003e\n\n\u003cp\u003e\u003cstrong\u003e​​​​​​​.\u003c/strong\u003e\u003c/p\u003e\n"},"policy":true,"priority":false,"order":102,"values":[]},{"_id":"64e6e423bb8be289fb77df01","valueIds":[],"value":{"vi":"365"},"selected":true,"type":"input","name":{"vi":"1 đổi 1 lên đến "},"image":"https://cdn.pico.vn/2025/11/20/176362901377710846474.svg","desktopIcon":"https://cdn.pico.vn/2025/11/15/176317497310243233303.svg","unit":{"_id":"64e6e287bb8be289fb77dea7","name":{"vi":"Ngày"}},"channels":["b2c"],"content":{"vi":"\u003ch1\u003e\u003cspan style=\"font-size:20px\"\u003e\u003cstrong\u003e1 ĐỔI 1 TRONG V\u0026Ograve;NG 365 NG\u0026Agrave;Y\u003c/strong\u003e\u003c/span\u003e\u003c/h1\u003e\n\n\u003cp\u003e\u003cspan style=\"font-size:14px\"\u003eVới gần \u003cstrong\u003e\u003cem\u003e20 năm\u003c/em\u003e\u003c/strong\u003e hoạt động trong lĩnh vực điện m\u0026aacute;y v\u0026agrave; phương ch\u0026acirc;m \u003cstrong\u003e\u003cem\u003e\u0026quot;Ti\u0026ecirc;n phong trong sứ mệnh phục vụ\u0026quot;\u003c/em\u003e\u003c/strong\u003e, Si\u0026ecirc;u thị Điện m\u0026aacute;y Pico đ\u0026atilde; tạo dựng được uy t\u0026iacute;n về chất lượng, gi\u0026aacute; th\u0026agrave;nh sản phẩm v\u0026agrave; chế độ hậu m\u0026atilde;i, chăm s\u0026oacute;c kh\u0026aacute;ch h\u0026agrave;ng tận t\u0026acirc;m. \u003c/span\u003e\u003c/p\u003e\n\n\u003cp\u003e\u003cspan style=\"font-size:14px\"\u003eĐể kh\u0026ocirc;ng ngừng n\u0026acirc;ng cao trải nghiệm mua h\u0026agrave;ng, Pico xin gửi đến Qu\u0026yacute; kh\u0026aacute;ch \u0026quot;\u003cem\u003e\u003cstrong\u003eCH\u0026Iacute;NH S\u0026Aacute;CH 1 ĐỔI 1 TRONG V\u0026Ograve;NG 365 NG\u0026Agrave;Y\u003c/strong\u003e\u003c/em\u003e\u0026quot;.\u003c/span\u003e\u003c/p\u003e\n\n\u003ch2\u003e\u003cspan style=\"font-size:14px\"\u003e\u003cstrong\u003e1. Thời gian \u0026aacute;p dụng chương tr\u0026igrave;nh:\u0026nbsp;\u003c/strong\u003eTừ ng\u0026agrave;y 01/12/2024\u003c/span\u003e\u003c/h2\u003e\n\n\u003ch2\u003e\u003cspan style=\"font-size:14px\"\u003e\u003cstrong\u003e2.\u0026nbsp;\u003c/strong\u003e\u003cstrong\u003eQuy định đổi/ trả sản phẩm\u003c/strong\u003e\u003c/span\u003e\u003c/h2\u003e\n\n\u003cp\u003e\u003cspan style=\"font-size:14px\"\u003eĐổi h\u0026agrave;ng trong v\u0026ograve;ng 1 năm\u0026nbsp;\u003cem\u003e(t\u0026iacute;nh từ thời điểm b\u0026agrave;n giao sản phẩm),\u003c/em\u003e\u0026nbsp;chỉ \u0026aacute;p dụng đối với những sản phẩm Pico b\u0026aacute;n từ ng\u0026agrave;y 01/12/2024 đến khi c\u0026oacute; th\u0026ocirc;ng b\u0026aacute;o mới.\u003c/span\u003e\u003c/p\u003e\n\n\u003cp style=\"text-align:center\"\u003eDanh mục c\u0026aacute;c sản phẩm \u0026aacute;p dụng Ch\u0026iacute;nh s\u0026aacute;ch\u003c/p\u003e\n\n\u003cp style=\"text-align:center\"\u003e\u0026quot;\u003cstrong\u003e1 đổi 1 l\u0026ecirc;n đến 365 ng\u0026agrave;y\u0026quot;\u003c/strong\u003e:\u003c/p\u003e\n\n\u003ctable cellspacing=\"0\" style=\"--tw-border-spacing-x:0; --tw-border-spacing-y:0; --tw-ring-color:rg